1233 bool InstCombinerImpl::replaceInInstruction(Value *V, Value *Old, Value *New,
1234                                             unsigned Depth) {
1235   // Conservatively limit replacement to two instructions upwards.
1236   if (Depth == 2)
1237     return false;
1238 
1239   assert(!isa<Constant>(Old) && "Only replace non-constant values");
1240 
1241   auto *I = dyn_cast<Instruction>(V);
1242   if (!I || !I->hasOneUse() ||
1243       !isSafeToSpeculativelyExecuteWithVariableReplaced(I))
1244     return false;
1245 
1246   // Forbid potentially lane-crossing instructions.
1247   if (Old->getType()->isVectorTy() && !isNotCrossLaneOperation(I))
1248     return false;
1249 
1250   bool Changed = false;
1251   for (Use &U : I->operands()) {
1252     if (U == Old) {
1253       replaceUse(U, New);
1254       Worklist.add(I);
1255       Changed = true;
1256     } else {
1257       Changed |= replaceInInstruction(U, Old, New, Depth + 1);
1258     }
1259   }
1260   return Changed;
1261 }
