1371 /// Fold the following code sequence:
1372 /// \code
1373 ///   %XeqZ = icmp eq i64 %X, %Z
1374 ///   %YeqZ = icmp eq i64 %Y, %Z
1375 ///   %XeqY = icmp eq i64 %X, %Y
1376 ///   %not.YeqZ = xor i1 %YeqZ, true
1377 ///   %and = select i1 %not.YeqZ, i1 %XeqY, i1 false
1378 ///   %equal = select i1 %XeqZ, i1 %YeqZ, i1 %and
1379 /// \code
1380 ///
1381 /// into:
1382 ///   %equal = icmp eq i64 %X, %Y
1383 Instruction *InstCombinerImpl::foldSelectEqualityTest(SelectInst &Sel) {
1384   Value *X, *Y, *Z;
1385   Value *XeqY, *XeqZ = Sel.getCondition(), *YeqZ = Sel.getTrueValue();
1386 
1387   if (!match(XeqZ, m_SpecificICmp(ICmpInst::ICMP_EQ, m_Value(X), m_Value(Z))))
1388     return nullptr;
1389 
1390   if (!match(YeqZ,
1391              m_c_SpecificICmp(ICmpInst::ICMP_EQ, m_Value(Y), m_Specific(Z))))
1392     std::swap(X, Z);
1393 
1394   if (!match(YeqZ,
1395              m_c_SpecificICmp(ICmpInst::ICMP_EQ, m_Value(Y), m_Specific(Z))))
1396     return nullptr;
1397 
1398   if (!match(Sel.getFalseValue(),
1399              m_c_LogicalAnd(m_Not(m_Specific(YeqZ)), m_Value(XeqY))))
1400     return nullptr;
1401 
1402   if (!match(XeqY,
1403              m_c_SpecificICmp(ICmpInst::ICMP_EQ, m_Specific(X), m_Specific(Y))))
1404     return nullptr;
1405 
1406   cast<ICmpInst>(XeqY)->setSameSign(false);
1407   return replaceInstUsesWith(Sel, XeqY);
1408 }
